fn u64_step(value: u64) -> u64 {
    if value >= 1_000 {
        100
    } else if value >= 100 {
        10
    } else {
        1
    }
}

fn apply_u64_step(current: u64, change: &StepChange<u64>, min: u64, max: u64) -> u64 {
    let next = if change.increase {
        current.saturating_add(change.delta)
    } else {
        current.saturating_sub(change.delta)
    };
    next.clamp(min, max)
}

fn apply_u8_step(current: u8, change: &StepChange<u8>, min: u8, max: u8) -> u8 {
    let next = if change.increase {
        current.saturating_add(change.delta)
    } else {
        current.saturating_sub(change.delta)
    };
    next.clamp(min, max)
}

fn activity_slider_normalized_value(slider: ActivitySlider, value: u64) -> u64 {
    match slider {
        ActivitySlider::IdleTimeout => value.clamp(
            ACTIVITY_IDLE_TIMEOUT_MIN_SECONDS,
            ACTIVITY_IDLE_TIMEOUT_MAX_SECONDS,
        ),
        ActivitySlider::CheckInterval => snap_to_step(value, ACTIVITY_CHECK_INTERVAL_STEP_MS)
            .clamp(
                ACTIVITY_CHECK_INTERVAL_MIN_MS,
                ACTIVITY_CHECK_INTERVAL_MAX_MS,
            ),
    }
}

fn snap_to_step(value: u64, step: u64) -> u64 {
    if step == 0 {
        return value;
    }
    ((value + (step / 2)) / step) * step
}

fn seconds_label(seconds: u64) -> String {
    duration_label_ms(
        seconds
            .clamp(
                ACTIVITY_IDLE_TIMEOUT_MIN_SECONDS,
                ACTIVITY_IDLE_TIMEOUT_MAX_SECONDS,
            )
            .saturating_mul(1_000),
    )
}

fn milliseconds_label(milliseconds: u64) -> String {
    duration_label_ms(
        snap_to_step(milliseconds, ACTIVITY_CHECK_INTERVAL_STEP_MS).clamp(
            ACTIVITY_CHECK_INTERVAL_MIN_MS,
            ACTIVITY_CHECK_INTERVAL_MAX_MS,
        ),
    )
}

fn duration_label_ms(milliseconds: u64) -> String {
    if milliseconds < 1_000 {
        return format!("{milliseconds} ms");
    }

    let (value, unit) = if milliseconds < 60_000 {
        (milliseconds as f64 / 1_000.0, "sec")
    } else if milliseconds < 3_600_000 {
        (milliseconds as f64 / 60_000.0, "min")
    } else {
        (milliseconds as f64 / 3_600_000.0, "hr")
    };

    rounded_duration_value(value, unit)
}

fn rounded_duration_value(value: f64, unit: &str) -> String {
    let rounded = (value * 10.0).round() / 10.0;
    if (rounded - rounded.round()).abs() < f64::EPSILON {
        format!("{} {unit}", rounded.round() as u64)
    } else {
        format!("{rounded:.1} {unit}")
    }
}

fn parse_u64_input(value: &str, min: u64, max: u64) -> Option<u64> {
    value.parse::<u64>().ok().map(|value| value.clamp(min, max))
}

fn parse_timer_resolution_input_100ns(
    value: &str,
    minimum_100ns: u32,
    maximum_100ns: u32,
) -> Option<u32> {
    let value = value.trim();
    let value = value
        .strip_suffix("ms")
        .or_else(|| value.strip_suffix("MS"))
        .or_else(|| value.strip_suffix("Ms"))
        .or_else(|| value.strip_suffix("mS"))
        .unwrap_or(value)
        .trim();
    let milliseconds = value
        .parse::<f64>()
        .ok()?
        .clamp(TIMER_RESOLUTION_INPUT_MIN_MS, TIMER_RESOLUTION_INPUT_MAX_MS);
    let value_100ns = (milliseconds * 10_000.0)
        .round()
        .clamp(1.0, u32::MAX as f64) as u32;
    Some(timer_resolution::normalize_desired_resolution(
        value_100ns,
        minimum_100ns,
        maximum_100ns,
    ))
}

fn cpu_usage_label(percent: Option<f32>) -> String {
    percent
        .map(|percent| format!("{percent:.1}%"))
        .unwrap_or_else(|| t!("dashboard.collecting").to_string())
}

fn cpu_frequency_label(frequency_mhz: Option<u32>) -> String {
    frequency_mhz
        .map(|frequency_mhz| {
            if frequency_mhz >= 1_000 {
                format!("{:.2} GHz", frequency_mhz as f64 / 1_000.0)
            } else {
                format!("{frequency_mhz} MHz")
            }
        })
        .unwrap_or_else(|| t!("dashboard.collecting").to_string())
}

fn memory_usage_label(percent: Option<f32>) -> String {
    percent
        .map(|percent| format!("{percent:.1}%"))
        .unwrap_or_else(|| t!("dashboard.collecting").to_string())
}

fn memory_usage_value_label(snapshot: MemoryUsageSnapshot) -> String {
    match (snapshot.used_physical_bytes, snapshot.total_physical_bytes) {
        (Some(used), Some(total)) => format_memory_used_total(used, total),
        _ => t!("dashboard.collecting").to_string(),
    }
}

fn memory_cache_value_label(snapshot: MemoryUsageSnapshot) -> String {
    snapshot
        .cached_physical_bytes
        .map(format_memory_capacity)
        .unwrap_or_else(|| t!("dashboard.collecting").to_string())
}

fn memory_cache_percent(snapshot: MemoryUsageSnapshot) -> Option<f32> {
    memory_bytes_percent(
        snapshot.cached_physical_bytes,
        snapshot.total_physical_bytes,
    )
}

fn refresh_due(now: Instant, next_refresh: &mut Instant, interval: Duration) -> bool {
    if now < *next_refresh {
        return false;
    }

    *next_refresh = now + interval;
    true
}

fn active_plan_guid(plans: &[PowerPlan]) -> Option<&str> {
    plans
        .iter()
        .find(|plan| plan.active)
        .map(|plan| plan.guid.as_str())
}

fn memory_bytes_percent(bytes: Option<u64>, total_bytes: Option<u64>) -> Option<f32> {
    let bytes = bytes?;
    let total_bytes = total_bytes?;
    if total_bytes == 0 {
        return None;
    }

    Some(((bytes as f64 / total_bytes as f64) * 100.0).clamp(0.0, 100.0) as f32)
}

fn io_usage_label(bytes_per_second: Option<f64>) -> String {
    bytes_per_second
        .map(format_bytes_per_second)
        .unwrap_or_else(|| t!("dashboard.collecting").to_string())
}

fn format_memory_used_total(used_bytes: u64, total_bytes: u64) -> String {
    let used = memory_capacity_parts(used_bytes);
    let total = memory_capacity_parts(total_bytes);

    if used.unit == total.unit && used.unit != "B" {
        format!(
            "{} / {} {}",
            format_capacity_number(used.value),
            format_capacity_number(total.value),
            used.unit
        )
    } else {
        format!(
            "{} / {}",
            format_memory_capacity(used_bytes),
            format_memory_capacity(total_bytes)
        )
    }
}

fn format_memory_capacity(bytes: u64) -> String {
    let capacity = memory_capacity_parts(bytes);
    if capacity.unit == "B" {
        format!("{} B", bytes)
    } else {
        format!(
            "{} {}",
            format_capacity_number(capacity.value),
            capacity.unit
        )
    }
}

fn format_capacity_number(value: f64) -> String {
    format!("{value:.1}")
}

fn memory_capacity_parts(bytes: u64) -> MemoryCapacityParts {
    const KIB: f64 = 1024.0;
    const MIB: f64 = KIB * 1024.0;
    const GIB: f64 = MIB * 1024.0;
    const TIB: f64 = GIB * 1024.0;

    let bytes = bytes as f64;
    if bytes >= TIB {
        MemoryCapacityParts {
            value: bytes / TIB,
            unit: "TB",
        }
    } else if bytes >= GIB {
        MemoryCapacityParts {
            value: bytes / GIB,
            unit: "GB",
        }
    } else if bytes >= MIB {
        MemoryCapacityParts {
            value: bytes / MIB,
            unit: "MB",
        }
    } else if bytes >= KIB {
        MemoryCapacityParts {
            value: bytes / KIB,
            unit: "KB",
        }
    } else {
        MemoryCapacityParts {
            value: bytes,
            unit: "B",
        }
    }
}

fn format_bytes_per_second(bytes_per_second: f64) -> String {
    const KIB: f64 = 1024.0;
    const MIB: f64 = KIB * 1024.0;
    const GIB: f64 = MIB * 1024.0;

    if bytes_per_second >= GIB {
        format!("{:.1} GB/s", bytes_per_second / GIB)
    } else if bytes_per_second >= MIB {
        format!("{:.1} MB/s", bytes_per_second / MIB)
    } else if bytes_per_second >= KIB {
        format!("{:.1} KB/s", bytes_per_second / KIB)
    } else {
        format!("{bytes_per_second:.0} B/s")
    }
}

fn input_hook_required(settings: &Settings) -> bool {
    settings.general.enabled
        && (activity_input_hook_required(settings) || app_suspension_input_hook_required(settings))
}

fn input_hook_config(settings: &Settings) -> InputHookConfig {
    let app_suspension = app_suspension_input_hook_required(settings);
    InputHookConfig {
        keyboard: settings.activity_mode.input_detection.keyboard || app_suspension,
        mouse: settings.activity_mode.input_detection.mouse || app_suspension,
    }
}

fn app_suspension_input_hook_required(settings: &Settings) -> bool {
    settings.app_suspension.enabled && !settings.smart_saver.enabled
}

fn activity_input_hook_required(settings: &Settings) -> bool {
    settings.activity_mode.enabled
        && settings.activity_mode.switch_to_performance_on_resume
        && settings
            .activity_mode
            .input_detection
            .keyboard_or_mouse_enabled()
        && (settings
            .activity_mode
            .power_plans
            .performance_guid
            .is_some()
            || settings.power_plans.performance_guid.is_some())
}

fn process_target_can_accept(target: SuggestionTarget, settings: &Settings, process: &str) -> bool {
    match target {
        SuggestionTarget::Foreground => {
            can_add_foreground_process(&settings.foreground_rules, process)
        }
        SuggestionTarget::EcoQos => can_add_eco_qos_process(&settings.eco_qos, process),
        SuggestionTarget::BackgroundCpu => {
            can_add_background_cpu_exclusion(&settings.background_cpu_restriction, process)
        }
        SuggestionTarget::MemoryTrim => {
            can_add_memory_trim_exclusion(&settings.memory_trim, process)
        }
        SuggestionTarget::Suspension => {
            can_add_suspension_process(&settings.app_suspension, process)
        }
        SuggestionTarget::CpuLimiter => can_add_cpu_limiter_process(&settings.cpu_limiter, process),
        SuggestionTarget::PerformanceMode => {
            can_add_performance_mode_process(&settings.performance_mode, process)
        }
        SuggestionTarget::WorkloadEngine => {
            can_add_workload_engine_process(&settings.workload_engine, process)
        }
        SuggestionTarget::ProcessPriority => {
            can_add_process_priority_exclusion(&settings.process_priority, process)
        }
        SuggestionTarget::ThreadPriority => {
            can_add_thread_priority_exclusion(&settings.thread_priority, process)
        }
        SuggestionTarget::PriorityBoost => {
            can_add_priority_boost_exclusion(&settings.priority_boost, process)
        }
        SuggestionTarget::IoPriority => {
            can_add_io_priority_exclusion(&settings.io_priority, process)
        }
        SuggestionTarget::GpuPriority => {
            can_add_gpu_priority_exclusion(&settings.gpu_priority, process)
        }
        SuggestionTarget::MemoryPriority => {
            can_add_memory_priority_exclusion(&settings.memory_priority, process)
        }
        SuggestionTarget::TimerResolution => {
            can_add_timer_resolution_process(&settings.timer_resolution, process)
        }
        SuggestionTarget::Affinity => can_add_affinity_process(&settings.cpu_affinity, process),
    }
}

fn can_add_process_candidate(
    process: &str,
    contains_process: impl FnOnce(&str) -> bool,
    is_builtin_excluded: impl FnOnce(&str) -> bool,
) -> bool {
    let process = process.trim();
    !process.is_empty() && !contains_process(process) && !is_builtin_excluded(process)
}

fn can_add_foreground_process(settings: &ForegroundRules, process: &str) -> bool {
    can_add_process_candidate(
        process,
        |process| {
            settings
                .rules
                .iter()
                .any(|rule| same_process_name(&rule.process_name, process))
        },
        |_| false,
    )
}

fn foreground_power_plan_override_guid(
    settings: &ForegroundRules,
    process_name: &str,
) -> Option<String> {
    settings
        .rules
        .iter()
        .find(|rule| rule.enabled && process_setting_matches(&rule.process_name, process_name))
        .and_then(|rule| rule.power_plan_guid.clone())
}

fn set_foreground_power_plan_override(
    settings: &mut ForegroundRules,
    process_name: &str,
    power_plan_guid: Option<String>,
) {
    if let Some(power_plan_guid) = power_plan_guid {
        if let Some(rule) = settings
            .rules
            .iter_mut()
            .find(|rule| process_setting_matches(&rule.process_name, process_name))
        {
            rule.enabled = true;
            rule.power_plan_guid = Some(power_plan_guid);
        } else {
            settings
                .rules
                .push(new_foreground_rule(process_name, Some(power_plan_guid)));
        }
    } else {
        settings
            .rules
            .retain(|rule| !process_setting_matches(&rule.process_name, process_name));
    }
}

fn new_foreground_rule(process: &str, power_plan_guid: Option<String>) -> ForegroundRule {
    let process_name = process.trim().to_ascii_lowercase();
    ForegroundRule {
        enabled: true,
        name: process_name.clone(),
        process_name,
        power_plan_guid,
    }
}

fn can_add_eco_qos_process(settings: &EcoQosSettings, process: &str) -> bool {
    can_add_process_candidate(
        process,
        |process| settings.contains_efficiency_exclusion(process),
        ecoqos::is_builtin_excluded,
    )
}

fn can_add_background_cpu_exclusion(
    settings: &BackgroundCpuRestrictionSettings,
    process: &str,
) -> bool {
    can_add_process_candidate(
        process,
        |process| settings.contains_exclusion(process),
        affinity::is_builtin_excluded,
    )
}

fn can_add_memory_trim_exclusion(settings: &MemoryTrimSettings, process: &str) -> bool {
    can_add_process_candidate(
        process,
        |process| {
            settings.exclusion_enabled_for(process)
                || settings
                    .exclusions
                    .iter()
                    .any(|rule| same_process_name(&rule.process_name, process))
        },
        memory_trim::is_builtin_excluded,
    )
}

fn new_process_exclusion_rule(process: &str) -> ProcessExclusionRule {
    ProcessExclusionRule {
        process_name: process.trim().to_ascii_lowercase(),
        ..Default::default()
    }
}

fn new_eco_qos_exclusion_rule(process: &str) -> EcoQosExclusionRule {
    EcoQosExclusionRule {
        enabled: true,
        process_name: process.trim().to_ascii_lowercase(),
    }
}

fn set_eco_qos_efficiency_exclusion(
    settings: &mut EcoQosSettings,
    process_name: &str,
    excluded: bool,
) {
    if excluded {
        if let Some(rule) = settings
            .efficiency_whitelist
            .iter_mut()
            .find(|rule| process_setting_matches(&rule.process_name, process_name))
        {
            rule.enabled = true;
        } else {
            settings
                .efficiency_whitelist
                .push(new_eco_qos_exclusion_rule(process_name));
        }
    } else {
        settings
            .efficiency_whitelist
            .retain(|rule| !process_setting_matches(&rule.process_name, process_name));
    }
}

fn set_process_exclusion(
    rules: &mut Vec<ProcessExclusionRule>,
    process_name: &str,
    excluded: bool,
) {
    if excluded {
        if let Some(rule) = rules
            .iter_mut()
            .find(|rule| process_setting_matches(&rule.process_name, process_name))
        {
            rule.enabled = true;
        } else {
            rules.push(new_process_exclusion_rule(process_name));
        }
    } else {
        rules.retain(|rule| !process_setting_matches(&rule.process_name, process_name));
    }
}

fn set_process_priority_rule(
    settings: &mut ProcessPrioritySettings,
    process_name: &str,
    priority: ProcessPrioritySetting,
) {
    let rule = settings
        .exclusions
        .iter_mut()
        .find(|rule| process_setting_matches(&rule.process_name, process_name));
    let rule = if let Some(rule) = rule {
        rule
    } else {
        settings
            .exclusions
            .push(new_process_exclusion_rule(process_name));
        settings.exclusions.last_mut().expect("rule was just added")
    };
    rule.enabled = true;
    rule.set_process_priority_override(true, priority);
    rule.set_process_priority_override(false, priority);
}

fn set_memory_priority_rule(
    settings: &mut MemoryPrioritySettings,
    process_name: &str,
    priority: ProcessMemoryPrioritySetting,
) {
    let rule = settings
        .exclusions
        .iter_mut()
        .find(|rule| process_setting_matches(&rule.process_name, process_name));
    let rule = if let Some(rule) = rule {
        rule
    } else {
        settings
            .exclusions
            .push(new_process_exclusion_rule(process_name));
        settings.exclusions.last_mut().expect("rule was just added")
    };
    rule.enabled = true;
    rule.set_memory_priority_override(true, priority);
    rule.set_memory_priority_override(false, priority);
}

fn can_add_suspension_process(settings: &AppSuspensionSettings, process: &str) -> bool {
    can_add_process_candidate(
        process,
        |process| settings.contains_suspendable_app(process),
        suspension::is_builtin_excluded,
    )
}

fn can_add_affinity_process(settings: &CpuAffinitySettings, process: &str) -> bool {
    can_add_process_candidate(
        process,
        |process| settings.contains_rule_for(process),
        affinity::is_builtin_excluded,
    )
}

fn can_add_workload_engine_process(settings: &WorkloadEngineSettings, process: &str) -> bool {
    can_add_process_candidate(
        process,
        |process| settings.contains_rule_for(process),
        workload_engine::is_builtin_excluded,
    )
}

